function myFunction() {
  const DRY_RUN = true;
}

function cleanupImportedTrainingEvents() {
  const DRY_RUN = true; // 第一次必须保持 true，只预览，不删除

  // 如果导入到了主日历，用 'primary'
  // 如果导入到了某个单独日历，把这里改成那个 calendar 的 ID
  const CALENDAR_ID = 'primary';

  // 覆盖 6 个月训练周期：[REDACTED_PHONE] 到 [REDACTED_PHONE]
  // end 是排他边界，所以写到 [REDACTED_PHONE]
  const START = new Date('[REDACTED_PHONE]T00:00:00+10:00');
  const END = new Date('[REDACTED_PHONE]T00:00:00+11:00');

  const calendar = CalendarApp.getCalendarById(CALENDAR_ID);
  if (!calendar) {
    throw new Error('找不到 calendar，请检查 CALENDAR_ID');
  }

  const events = calendar.getEvents(START, END);

  const trainingTitlePattern =
    /^(W\d{2}D\d{2}\s(晨间启动|晚间打卡)｜|W\d{2}\s周复盘｜)/;

  const matched = events.filter(event =>
    trainingTitlePattern.test(event.getTitle())
  );

  console.log(`匹配到 ${matched.length} 个训练事件`);
  matched.forEach(event => {
    console.log(`${event.getStartTime().toISOString()} | ${event.getTitle()}`);
  });

  if (DRY_RUN) {
    console.log('DRY_RUN=true：本次只是预览，没有删除。确认无误后把 DRY_RUN 改成 false 再运行。');
    return;
  }

  matched.forEach(event => {
    event.deleteEvent();
  });

  console.log(`已删除 ${matched.length} 个训练事件`);
}

cleanupImportedTrainingEvents()这个运行不了啊

你这个运行不了，最可能有 **3 个原因**：

1. **`CalendarApp.getCalendarById('primary')` 在 Apps Script 里不稳**  
   Google Calendar REST API 常用 `primary`，但 Apps Script 的 `CalendarApp` 里默认日历应该用 `CalendarApp.getDefaultCalendar()`；官方文档也说明 `getDefaultCalendar()` 是获取用户默认日历的方法，默认日历的 ID 通常是你的邮箱地址，而不是 `primary`。citeturn572732view0turn572732view1

2. **最后一行 `cleanupImportedTrainingEvents()` 不要写**  
   在 Apps Script 里不是像 Node.js 一样直接在文件底部调用。你应该在顶部工具栏的函数下拉框里选择函数，然后点 **Run**。

3. **`myFunction()` 没有用**  
   你写的：

```javascript
function myFunction() {
  const DRY_RUN = true;
}
```

这个函数里面的 `DRY_RUN` 是局部变量，对下面的清理函数没有任何影响，可以删掉。

